[HttpGet("{invoiceId}")]
public async Task<ActionResult<Invoice>> GetInvoice(int invoiceId)
{
    // Check if the user has permission to view this invoice
    if (!User.HasClaim(ClaimTypes.Permission, "ViewInvoices"))
    {
        return Forbid();
    }

    // Retrieve the invoice from the database using the invoice ID
    var invoice = await _context.Invoices.FindAsync(invoiceId);

    if (invoice == null)
    {
        return NotFound();
    }

    return Ok(invoice);
}